B.JX=new A.b_("level_2","Level 2 \u2014 PDA Boss","Build a PDA that matches the hidden stack-based target machine. Study the transition format and think carefully about what language this could be.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = <<ha>>\n      n4 = E\n      n5 = F\n      n0 = (723.3, 204.7)\n      n1 = (1139.3, 259.3)\n      n2 = (1196.0, 527.3)\n      n3 = (739.3, 705.3)\n      n4 = (345.3, 504.7)\n      n5 = (345.3, 277.3)\n      n0 to n5 = 0,~|X\n      n0 to n1 = 1,~|Y\n      n1 to n1 = 1,~|Y\n      n1 to n2 = 0,Y|~\n      n2 to n1 = 1,\u2205|Y\n      n2 to n5 = 0,\u2205|X\n      n4 to n1 = 1,\u2205|Y\n      n4 to n5 = 0,\u2205|X\n      n5 to n4 = 1,X|~\n      n5 to n5 = 0,~|X\n      n4 to n4 = 1,X|~\n      n4 to n3 = \u2205,\u2205|~\n      n2 to n3 = \u2205,\u2205|~\n      n2 to n2 = 0,Y|~\n      l0(0,~|X) curve = -2.9\n      l3(0,Y|~) curve = 62.2\n      l4(1,\u2205|Y) curve = 55.1\n      l5(0,\u2205|X) curve = 39.9\n      l6(1,\u2205|Y) curve = 16.9\n      l7(0,\u2205|X) curve = -8.2\n      l8(1,X|~) curve = -105.4\n      l2(1,~|Y) loop angle = -0.7988\n      l9(0,~|X) loop angle = -1.5708\n      l10(1,X|~) loop angle = 1.7686\n      l13(0,Y|~) loop angle = -0.0754\n      to n0 angle = -1.0000, 0.0000\n    ",B.aY,B.U5,0.5,"pda")
