B.KC=new A.b_("tm_palindrome","TM: Palindrome","Build a TM over {a, b} that accepts palindromes of any length.\nStrategy: repeatedly peel the first and last character and verify they match.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (640.0, 200.0)\n      C = (1020.0, 200.0)\n      D = (1020.0, 540.0)\n      E = (640.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to E = aXL\n      C to C = aaR\n      C to C = bbR\n      C to D = bXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.6000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.6000\n      l8(aaL) loop angle = 1.5708\n      l9(bbL) loop angle = 0.6000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.6000\n      aXR curve = 70.0\n      bXR curve = -70.0\n      aXL curve = -70.0\n      bXL curve = 70.0\n      to A angle = -1.0000, 0.0000\n    ",B.bu,B.U7,0.3,"tm")
